	@Test
	public void committedWriteInvalidatesEntry() throws Exception {
		loadDefaultData();
		buildEntry(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true);
		assertThat(cache.lookup(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true)).isNotNull();
		long bytesBefore = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		assertThat(bytesBefore).isGreaterThan(0);

		tripleStore.startTransaction();
		tripleStore.storeTriple(500, 10, 9999, 0, true);
		tripleStore.commit();

		assertThat(cache.lookup(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true))
				.as("a committed write must invalidate the entry")
				.isNull();
		assertThat(LmdbCsrAdjacencyCache.STALE_DROPS.get()).isEqualTo(1);
		assertThat(LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get()).isLessThan(bytesBefore);

		// rebuild sees the new quad
		buildEntry(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true);
		LmdbCsrAdjacencyCache.CsrEntry rebuilt = cache.lookup(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true);
		assertSameQuads(cacheProbe(rebuilt, 500, 10, -1, LmdbCsrAdjacencyCache.BY_SUBJECT),
				referenceProbe(500, 10, -1, -1));
	}

